def group_anagrams(strs):
    d = {}
    for w in strs:
        key = "".join(sorted(w))
        d.setdefault(key, []).append(w)
    return list(d.values())

def two_sum_sorted(nums, target):
    l = 0
    r = len(nums) - 1
    while l < r:
        s = nums[l] + nums[r]
        if s == target:
            return [l + 1, r + 1]
        if s < target:
            l = l + 1
        else:
            r = r - 1
    return []

def is_valid(s):
    pairs = {")": "(", "]": "[", "}": "{"}
    stack = []
    for ch in s:
        if ch in pairs:
            if not stack or stack.pop() != pairs[ch]:
                return False
        else:
            stack.append(ch)
    return len(stack) == 0

def daily_temperatures(temps):
    ans = [0] * len(temps)
    stack = []
    for i, t in enumerate(temps):
        while stack and temps[stack[-1]] < t:
            j = stack.pop()
            ans[j] = i - j
        stack.append(i)
    return ans

def max_profit(prices):
    min_so_far = prices[0]
    best = 0
    for p in prices:
        if p - min_so_far > best:
            best = p - min_so_far
        if p < min_so_far:
            min_so_far = p
    return best

def length_of_longest(s):
    seen = set()
    l = 0
    best = 0
    for r in range(len(s)):
        while s[r] in seen:
            seen.remove(s[l])
            l = l + 1
        seen.add(s[r])
        if r - l + 1 > best:
            best = r - l + 1
    return best

