from collections import deque
# shortest hops from start on an unweighted graph (adjacency dict)
def bfs_dist(graph, start):
    dist = {start: 0}
    q = deque([start])
    while q:
        node = q.popleft()
        for nxt in graph[node]:
            if nxt not in dist:          # first sighting == shortest
                dist[nxt] = dist[node] + 1
                q.append(nxt)
    return dist

