from collections import deque
def count_islands(grid):
    if not grid:
        return 0
    R, C = len(grid), len(grid[0])
    seen = set()
    count = 0
    for r in range(R):
        for c in range(C):
            if grid[r][c] == 1 and (r, c) not in seen:
                count += 1
                q = deque([(r, c)])
                seen.add((r, c))
                while q:
                    y, x = q.popleft()
                    for dy, dx in ((1,0),(-1,0),(0,1),(0,-1)):
                        ny, nx = y + dy, x + dx
                        if 0 <= ny < R and 0 <= nx < C and \
                           grid[ny][nx] == 1 and (ny, nx) not in seen:
                            seen.add((ny, nx))
                            q.append((ny, nx))
    return count

