# climbing stairs: how many ways to reach step n (1 or 2 at a time)
def climb(n):
    if n <= 2:
        return n
    a, b = 1, 2            # ways to reach step 1 and step 2
    for _ in range(3, n + 1):
        a, b = b, a + b    # dp[i] = dp[i-1] + dp[i-2]
    return b
